const owner = 'oliversoft-tech';
const repo = 'fastroute-changemanagement';

const token = String(
  ($env && $env.GITHUB_TOKEN) ||
  (typeof process !== 'undefined' && process.env ? process.env.GITHUB_TOKEN : '') ||
  ''
).trim();

if (!token) {
  throw new Error('[Approve Review + Run Full Pipeline] GITHUB_TOKEN ausente no environment.');
}

const payload = {
  event_type: 'governance-release',
  client_payload: {
    source_repo: 'fastroute-changemanagement',
    source_event: 'manual_approval',
    source_ref: 'main',
    domain_ref: 'main',
    api_ref: 'main',
    mobile_ref: 'main',
    mobile_profile: 'preview',
    run_ci: true,
    run_release: true,
    deploy_api: true,
    publish_domain: true,
    auto_implement: false,
    approved: true
  }
};

const url = `https://api.github.com/repos/${owner}/${repo}/dispatches`;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: {
      Authorization: 'Bearer ' + token,
      Accept: 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    },
    body: payload,
    json: true,
  });

  return [{
    json: {
      status: 'dispatched',
      workflow_target: `${owner}/${repo}`,
      event_type: payload.event_type,
      client_payload: payload.client_payload,
      dispatched_at: new Date().toISOString(),
    }
  }];
} catch (e) {
  const body = e?.response?.body || e?.message || e;
  throw new Error('[Approve Review + Run Full Pipeline] falha no dispatch: ' + (typeof body === 'string' ? body : JSON.stringify(body)));
}
